patch:
Index: templates/index.html
===================================================================
--- templates/index.html	
+++ templates/index.html	
@@ -0,0 +1,35 @@
+<!DOCTYPE html>
+<html lang="pt-BR">
+<head>
+    <meta charset="UTF-8">
+    <meta name="viewport" content="width=device-width, initial-scale=1.0">
+    <title>Download - Instalador</title>
+    <style>
+        * { margin: 0; padding: 0; box-sizing: border-box; }
+        body { font-family: 'Segoe UI', sans-serif; background: #0f0f0f; color: #e0e0e0; min-height: 100vh; display: flex; justify-content: center; align-items: center; }
+        .container { background: #1a1a2e; border-radius: 16px; padding: 48px; max-width: 520px; width: 90%; box-shadow: 0 8px 32px rgba(0,0,0,0.4); text-align: center; }
+        h1 { font-size: 1.8rem; margin-bottom: 8px; color: #ffffff; }
+        .subtitle { color: #888; margin-bottom: 32px; }
+        .file-list { list-style: none; }
+        .file-list li { margin-bottom: 12px; }
+        .file-list a { display: inline-block; background: #16213e; color: #00d4ff; text-decoration: none; padding: 12px 28px; border-radius: 8px; font-size: 1rem; transition: background 0.2s; }
+        .file-list a:hover { background: #1a1a4e; }
+        .empty { color: #666; font-style: italic; }
+    </style>
+</head>
+<body>
+    <div class="container">
+        <h1>Instalador</h1>
+        <p class="subtitle">Baixe o instalador mais recente</p>
+        {% if files %}
+        <ul class="file-list">
+            {% for file in files %}
+            <li><a href="/download/{{ file }}">{{ file }}</a></li>
+            {% endfor %}
+        </ul>
+        {% else %}
+        <p class="empty">Nenhum instalador disponivel no momento.</p>
+        {% endif %}
+    </div>
+</body>
+</html>
